const input = $input.item.json.body;
const language = input.language || 'zh';
const outputLanguage = input.outputLanguage || (language === 'en' ? 'English' : 'Chinese');

const phaseInfo = {
  engage: { label: 'Engage', description: '建立情感连接与情境导入，激发好奇心和参与动机', idPrefix: 'e' },
  empower: { label: 'Empower', description: '输入语言知识与SEL技能，进行体感探索', idPrefix: 'em' },
  execute: { label: 'Execute', description: '通过艺术表达完成终极产出任务，体验合作分享', idPrefix: 'ex' },
  elevate: { label: 'Elevate', description: '反思、内化并建立积极情绪闭环', idPrefix: 'el' }
};

const phaseKey = input.phaseKey || 'engage';
const info = phaseInfo[phaseKey];

const phaseInfoEn = {
  engage: { label: 'Engage', description: 'Build emotional connection, introduce the context, and spark curiosity and motivation' },
  empower: { label: 'Empower', description: 'Introduce language knowledge and SEL skills through embodied exploration' },
  execute: { label: 'Execute', description: 'Complete the final output task through creative expression and collaborative sharing' },
  elevate: { label: 'Elevate', description: 'Reflect, internalize learning, and close the positive emotion loop' }
};
if (language === 'en' && phaseInfoEn[phaseKey]) {
  info.label = phaseInfoEn[phaseKey].label;
  info.description = phaseInfoEn[phaseKey].description;
}
const existingStepCount = input.existingStepCount || 0;
const insertIndex = input.insertIndex != null ? input.insertIndex : existingStepCount;
const nextIndex = existingStepCount + 1;
const stepId = `${info.idPrefix}${nextIndex}`;

let existingStepsStr = '暂无已有环节';
if (input.currentSteps && input.currentSteps.length > 0) {
  existingStepsStr = input.currentSteps.map((s, i) => `${i+1}. ${s.title} (${s.time})`).join('\n');
}

let insertContextStr = '';
if (insertIndex >= existingStepCount) {
  insertContextStr = '新环节应接续在所有已有环节之后，作为该阶段的最后一个环节。';
} else {
  const prev = input.prevStep;
  const next = input.nextStep;
  let parts = [`新环节将插入到第 ${insertIndex + 1} 个位置。`];
  if (prev) {
    parts.push(`前置环节：${prev.title}（${prev.time}）—— 目标：${prev.objective || '无'}`);
  } else {
    parts.push('这是该阶段的第一个环节。');
  }
  if (next) {
    parts.push(`后续环节：${next.title}（${next.time}）—— 目标：${next.objective || '无'}`);
    parts.push('新环节必须在叙事和教学逻辑上衔接前后环节，起到承上启下的过渡作用。');
  }
  insertContextStr = parts.join('\n');
}

let otherPhasesStr = '无';
if (input.otherPhases) {
  try {
    otherPhasesStr = typeof input.otherPhases === 'string' ? input.otherPhases : JSON.stringify(input.otherPhases, null, 2);
  } catch (e) {
    otherPhasesStr = '无法解析';
  }
}

return {
  language,
  outputLanguage,
  age: input.age || '7-9岁',
  duration: input.duration || '60分钟',
  scale: input.scale || '≤ 8人',
  title: input.title || '未命名课件',
  vocabulary: (input.vocabulary && input.vocabulary.length > 0) ? (Array.isArray(input.vocabulary) ? input.vocabulary.join(', ') : input.vocabulary) : '请根据主题推荐词汇',
  grammar: (input.grammar && input.grammar.length > 0) ? (Array.isArray(input.grammar) ? input.grammar.join(', ') : input.grammar) : '请根据主题推荐句型',
  theme: input.theme || '默认主题',
  requirements: input.requirements || '',
  phaseKey,
  phaseLabel: info.label,
  phaseDescription: info.description,
  stepId,
  nextIndex,
  existingSteps: existingStepsStr,
  insertContext: insertContextStr,
  otherPhases: otherPhasesStr
};

